package com.chaobo.scm.supplier.interfaces.web;
import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.qualification.*;import com.chaobo.scm.supplier.application.shared.CommandResult;import com.chaobo.scm.supplier.infrastructure.security.CommandContextFactory;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.security.core.*;import org.springframework.security.core.annotation.*;import org.springframework.security.oauth2.jwt.*;import org.springframework.web.bind.annotation.*;import java.time.*;
@RestController @RequestMapping("/api/supplier/v1/qualifications") public class SupplierQualificationController {private final SupplierQualificationApplicationService service;private final CommandContextFactory contexts;public SupplierQualificationController(SupplierQualificationApplicationService service,CommandContextFactory contexts){this.service=service;this.contexts=contexts;}@GetMapping public ApiResponse<PageResult<SupplierQualificationView>> page(@RequestParam(required=false)Long supplierId,@RequestParam(required=false)Integer status,@RequestParam(defaultValue="1")int pageNo,@RequestParam(defaultValue="20")int pageSize,@AuthenticationPrincipal Jwt jwt,HttpServletRequest request){return ApiResponse.success(service.page(supplierId,scope(jwt),status,pageNo,pageSize),request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}@GetMapping("/{id}") public ApiResponse<SupplierQualificationView> detail(@PathVariable long id,@AuthenticationPrincipal Jwt jwt,HttpServletRequest request){return ApiResponse.success(service.detail(id,scope(jwt)),request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}@PostMapping public ApiResponse<CommandResult> submit(@Valid @RequestBody Submit body,HttpServletRequest request,Authentication auth){return ok(service.submit(body.supplierId(),body.qualificationType(),body.qualificationNo(),body.validFrom(),body.validTo(),body.attachmentUrl(),contexts.create(request,auth)),request);}@PostMapping("/{id}/approve")public ApiResponse<CommandResult> approve(@PathVariable long id,@Valid @RequestBody Approve body,HttpServletRequest request,Authentication auth){return ok(service.approve(id,body.version(),body.remark(),contexts.create(request,auth)),request);}@PostMapping("/{id}/reject")public ApiResponse<CommandResult> reject(@PathVariable long id,@Valid @RequestBody Reject body,HttpServletRequest request,Authentication auth){return ok(service.reject(id,body.version(),body.reason(),contexts.create(request,auth)),request);}private ApiResponse<CommandResult> ok(CommandResult result,HttpServletRequest request){return ApiResponse.success(result,request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}private Long scope(Jwt jwt){Number n=jwt.hasClaim("supplier_id")?jwt.getClaim("supplier_id"):null;return n==null?null:n.longValue();}public record Submit(@Positive long supplierId,@NotBlank String qualificationType,@NotBlank String qualificationNo,@NotNull LocalDate validFrom,@NotNull LocalDate validTo,@NotBlank String attachmentUrl){}public record Approve(@PositiveOrZero int version,String remark){}public record Reject(@PositiveOrZero int version,@NotBlank String reason){}}
